UPDATE ss_sandbox_record
SET last_access_time = #{lastAccessTime,jdbcType=TIMESTAMP},
    update_time = #{lastAccessTime,jdbcType=TIMESTAMP}
WHERE id = #{id,jdbcType=BIGINT}
  AND status = 'RUNNING'

