SELECT FROM ss_sandbox_record WHERE status = 'RUNNING' AND (lease_policy IN ('REMOTE_AUTO_EXPIRE', 'MANUAL') OR auto_release = 0) AND sandbox_id IS NOT NULL AND sandbox_id != '' AND timeout_seconds IS NOT NULL AND timeout_seconds > 0 AND next_renew_at IS NOT NULL AND next_renew_at <= #{now,jdbcType=TIMESTAMP}
AND (next_renew_at > #{cursorTime,jdbcType=TIMESTAMP} OR (next_renew_at = #{cursorTime,jdbcType=TIMESTAMP} AND id > #{cursorId,jdbcType=BIGINT}))
ORDER BY next_renew_at ASC, id ASC LIMIT #{limit}

SELECT FROM ss_sandbox_record WHERE status != 'RELEASED' AND sandbox_id IS NOT NULL AND sandbox_id != ''
AND (update_time > #{cursorTime,jdbcType=TIMESTAMP} OR (update_time = #{cursorTime,jdbcType=TIMESTAMP} AND id > #{cursorId,jdbcType=BIGINT}))
ORDER BY update_time ASC, id ASC LIMIT #{limit}

SELECT FROM ss_sandbox_record
AND status = #{status,jdbcType=VARCHAR}
AND ( user_code LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR endpoint LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR chat_id LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR CAST(resource_id AS VARCHAR) LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') )
ORDER BY create_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM ss_sandbox_record
AND status = #{status,jdbcType=VARCHAR}
AND ( user_code LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR endpoint LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR chat_id LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') OR CAST(resource_id AS VARCHAR) LIKE CONCAT('%', #{keyword,jdbcType=VARCHAR}, '%') )
